import{_ as d,o as e,c as o,a2 as r}from"./chunks/framework.Dvn0Uh9o.js";const p=JSON.parse('{"title":"Fields Properties","description":"","frontmatter":{},"headers":[],"relativePath":"api-reference/fields-properties.md","filePath":"api-reference/fields-properties.md","lastUpdated":1783374406000}'),a={name:"api-reference/fields-properties.md"};function c(i,t,n,l,s,h){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="fields-properties" tabindex="-1">Fields Properties <a class="header-anchor" href="#fields-properties" aria-label="Permalink to &quot;Fields Properties&quot;">​</a></h1><p>Every field exposes <strong>editable props</strong> (set during definition, mutable at runtime) and <strong>computed props</strong> (read-only values derived from field state).</p><hr><h2 id="editable-props" tabindex="-1">Editable Props <a class="header-anchor" href="#editable-props" aria-label="Permalink to &quot;Editable Props&quot;">​</a></h2><p>Props you can define when creating fields and modify at runtime via <code>field.set(prop, value)</code>.</p><h3 id="value-display" tabindex="-1">Value &amp; Display <a class="header-anchor" href="#value-display" aria-label="Permalink to &quot;Value &amp; Display&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>type</code></td><td>string</td><td><code>&quot;text&quot;</code></td><td>HTML input type (<code>text</code>, <code>email</code>, <code>checkbox</code>, <code>file</code>, <code>number</code>, etc.)</td></tr><tr><td><code>value</code></td><td>any</td><td><code>undefined</code></td><td>Current field value</td></tr><tr><td><code>initial</code></td><td>any</td><td><code>undefined</code></td><td>Initial value on mount</td></tr><tr><td><code>default</code></td><td>any</td><td><code>undefined</code></td><td>Value used when <code>reset()</code> is called</td></tr><tr><td><code>label</code></td><td>string</td><td><code>&quot;&quot;</code></td><td>Human-readable field label</td></tr><tr><td><code>placeholder</code></td><td>string</td><td><code>&quot;&quot;</code></td><td>Placeholder text for the input</td></tr><tr><td><code>extra</code></td><td>any</td><td><code>null</code></td><td>Arbitrary metadata (useful for select options, custom data)</td></tr></tbody></table><h3 id="input-behavior" tabindex="-1">Input Behavior <a class="header-anchor" href="#input-behavior" aria-label="Permalink to &quot;Input Behavior&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>disabled</code></td><td>boolean</td><td><code>false</code></td><td>Field disabled state</td></tr><tr><td><code>deleted</code></td><td>boolean</td><td><code>false</code></td><td>Soft-deleted state (requires <code>softDelete</code> option)</td></tr><tr><td><code>nullable</code></td><td>boolean</td><td><code>false</code></td><td>Allow <code>null</code> as a field value</td></tr><tr><td><code>autoFocus</code></td><td>boolean</td><td><code>false</code></td><td>Focus this field on form initialization</td></tr><tr><td><code>inputMode</code></td><td>string</td><td><code>undefined</code></td><td>Mobile keyboard mode: <code>none</code>, <code>text</code>, <code>decimal</code>, <code>numeric</code>, <code>tel</code>, <code>search</code>, <code>email</code>, <code>url</code></td></tr><tr><td><code>autoComplete</code></td><td>string</td><td><code>undefined</code></td><td>HTML <code>autocomplete</code> attribute</td></tr><tr><td><code>ref</code></td><td>React Ref</td><td><code>undefined</code></td><td>React ref, populated automatically when <code>bind()</code> is used</td></tr></tbody></table><h3 id="validation" tabindex="-1">Validation <a class="header-anchor" href="#validation" aria-label="Permalink to &quot;Validation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>rules</code></td><td>string</td><td><code>null</code></td><td>DVR validation rules (e.g. <code>&quot;required&amp;#124;email&amp;#124;min:6&quot;</code>)</td></tr><tr><td><code>validators</code></td><td>array</td><td><code>null</code></td><td>VJF validation functions</td></tr><tr><td><code>validatedWith</code></td><td>string</td><td><code>&quot;value&quot;</code></td><td>Field prop to validate instead of <code>value</code> (see <a href="./../extra/validated-value">validatedValue</a>)</td></tr><tr><td><code>related</code></td><td>string[]</td><td><code>[]</code></td><td>Other field paths to re-validate when this field changes</td></tr></tbody></table><h3 id="converters-computed" tabindex="-1">Converters &amp; Computed <a class="header-anchor" href="#converters-computed" aria-label="Permalink to &quot;Converters &amp; Computed&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>converter</code></td><td>function</td><td>identity</td><td>Function controlling the <code>value</code> computed prop output</td></tr><tr><td><code>converters</code></td><td>function[]</td><td>-</td><td>Array of converter functions</td></tr><tr><td><code>input</code></td><td>function</td><td>identity</td><td>Input converter: maps user input to stored value</td></tr><tr><td><code>output</code></td><td>function</td><td>identity</td><td>Output converter: maps stored value to output</td></tr><tr><td><code>computed</code></td><td>function</td><td><code>undefined</code></td><td>Dynamic value function: <code>({ form, field }) =&gt; value</code></td></tr></tbody></table><h3 id="bindings-options" tabindex="-1">Bindings &amp; Options <a class="header-anchor" href="#bindings-options" aria-label="Permalink to &quot;Bindings &amp; Options&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>bindings</code></td><td>string</td><td><code>&quot;default&quot;</code></td><td>Key of the registered binding template/rewriter to use</td></tr><tr><td><code>options</code></td><td>object</td><td><code>{}</code></td><td>Per-field <a href="./../form/form-options">Form Options</a>, with fallback on global options</td></tr><tr><td><code>class</code></td><td>class</td><td><code>undefined</code></td><td>Custom Field class (unified mode only, must extend <code>Form.Field</code>)</td></tr><tr><td><code>classes</code></td><td>object</td><td><code>undefined</code></td><td>Custom Field classes keyed by field path (separated mode only)</td></tr></tbody></table><h3 id="events-mobx" tabindex="-1">Events &amp; MobX <a class="header-anchor" href="#events-mobx" aria-label="Permalink to &quot;Events &amp; MobX&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>hooks</code></td><td>object</td><td><code>{}</code></td><td>Event hook functions</td></tr><tr><td><code>handlers</code></td><td>object</td><td><code>{}</code></td><td>Event handler functions</td></tr><tr><td><code>observers</code></td><td>array</td><td><code>null</code></td><td>MobX observers on field props or fields map. Auto-loaded for dynamic arrays.</td></tr><tr><td><code>interceptors</code></td><td>array</td><td><code>null</code></td><td>MobX interceptors on field props or fields map. Auto-loaded for dynamic arrays.</td></tr></tbody></table><h3 id="nested" tabindex="-1">Nested <a class="header-anchor" href="#nested" aria-label="Permalink to &quot;Nested&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>fields</code></td><td>array</td><td><code>undefined</code></td><td>Nested sub-field definitions</td></tr><tr><td><code>name</code></td><td>string</td><td><code>key</code></td><td>Overrides the object key as field name (array syntax)</td></tr></tbody></table><hr><h2 id="computed-props" tabindex="-1">Computed Props <a class="header-anchor" href="#computed-props" aria-label="Permalink to &quot;Computed Props&quot;">​</a></h2><p>Read-only properties derived from the field state. Accessible at runtime (e.g. <code>field.isValid</code>, <code>field.error</code>).</p><h3 id="validation-state" tabindex="-1">Validation State <a class="header-anchor" href="#validation-state" aria-label="Permalink to &quot;Validation State&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>MobX</th><th>Description</th></tr></thead><tbody><tr><td><code>isValid</code></td><td>boolean</td><td>computed</td><td><code>true</code> if the field and all nested fields pass validation</td></tr><tr><td><code>hasError</code></td><td>boolean</td><td>computed</td><td><code>true</code> if the field or any nested field has errors</td></tr><tr><td><code>error</code></td><td>string</td><td>computed</td><td>First error message (<code>null</code> if no error, <code>null</code> when <code>showError</code> is <code>false</code>)</td></tr><tr><td><code>errorSync</code></td><td>string</td><td>observable</td><td>Synchronous error message</td></tr><tr><td><code>errorAsync</code></td><td>string</td><td>observable</td><td>Asynchronous error message (from async validation)</td></tr><tr><td><code>validating</code></td><td>boolean</td><td>computed</td><td><code>true</code> while validation is in progress</td></tr><tr><td><code>validated</code></td><td>int</td><td>computed</td><td>Number of times the field has been validated</td></tr></tbody></table><h3 id="identity-structure" tabindex="-1">Identity &amp; Structure <a class="header-anchor" href="#identity-structure" aria-label="Permalink to &quot;Identity &amp; Structure&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>MobX</th><th>Description</th></tr></thead><tbody><tr><td><code>key</code></td><td>string</td><td>-</td><td>Field key (same as <code>name</code> if not provided)</td></tr><tr><td><code>name</code></td><td>string</td><td>-</td><td>Field name (same as <code>key</code> if not provided)</td></tr><tr><td><code>path</code></td><td>string</td><td>-</td><td>Full field path (dot-notated for nested fields, e.g. <code>&quot;address.city&quot;</code>)</td></tr><tr><td><code>size</code></td><td>int</td><td>computed</td><td>Number of child fields (0 for leaf fields)</td></tr><tr><td><code>id</code></td><td>string</td><td>-</td><td>Unique field ID (generated by <code>uniqueId</code> option)</td></tr><tr><td><code>hasNestedFields</code></td><td>boolean</td><td>computed</td><td><code>true</code> if the field contains nested sub-fields</td></tr><tr><td><code>hasIncrementalKeys</code></td><td>boolean</td><td>computed</td><td><code>true</code> if nested fields use incremental numeric keys</td></tr></tbody></table><h3 id="state-interaction" tabindex="-1">State &amp; Interaction <a class="header-anchor" href="#state-interaction" aria-label="Permalink to &quot;State &amp; Interaction&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>MobX</th><th>Description</th></tr></thead><tbody><tr><td><code>focused</code></td><td>boolean</td><td>computed</td><td><code>true</code> if the field is currently focused</td></tr><tr><td><code>blurred</code></td><td>boolean</td><td>computed</td><td><code>true</code> if the field has lost focus at least once</td></tr><tr><td><code>touched</code></td><td>boolean</td><td>computed</td><td><code>true</code> if the field has been focused at least once</td></tr><tr><td><code>changed</code></td><td>int</td><td>computed</td><td>Number of times the field value has changed</td></tr><tr><td><code>submitting</code></td><td>boolean</td><td>computed</td><td><code>true</code> while the form/fieldset is submitting</td></tr><tr><td><code>submitted</code></td><td>int</td><td>computed</td><td>Number of times the fieldset has been submitted</td></tr><tr><td><code>actionRunning</code></td><td>boolean</td><td>computed</td><td><code>true</code> while a clear, reset, or submit action is in progress (useful for loading spinners)</td></tr><tr><td><code>resetting</code></td><td>boolean</td><td>observable</td><td><code>true</code> while the field is being reset</td></tr><tr><td><code>clearing</code></td><td>boolean</td><td>observable</td><td><code>true</code> while the field is being cleared</td></tr></tbody></table><h3 id="value-comparison" tabindex="-1">Value Comparison <a class="header-anchor" href="#value-comparison" aria-label="Permalink to &quot;Value Comparison&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>MobX</th><th>Description</th></tr></thead><tbody><tr><td><code>isDirty</code></td><td>boolean</td><td>computed</td><td><code>true</code> if the current value differs from the initial value</td></tr><tr><td><code>isPristine</code></td><td>boolean</td><td>computed</td><td><code>true</code> if the current value equals the initial value</td></tr><tr><td><code>isDefault</code></td><td>boolean</td><td>computed</td><td><code>true</code> if the current value equals the default value</td></tr><tr><td><code>isEmpty</code></td><td>boolean</td><td>computed</td><td><code>true</code> if the field value is empty (delegates to child fields for nested fields)</td></tr></tbody></table><h3 id="special" tabindex="-1">Special <a class="header-anchor" href="#special" aria-label="Permalink to &quot;Special&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Type</th><th>MobX</th><th>Description</th></tr></thead><tbody><tr><td><code>checked</code></td><td>any</td><td>computed</td><td>Current value when <code>type</code> is <code>&quot;checkbox&quot;</code>; <code>undefined</code> otherwise</td></tr><tr><td><code>validatedValue</code></td><td>any</td><td>computed</td><td>Value of the field prop specified by <code>validatedWith</code> (default: <code>&quot;value&quot;</code>)</td></tr><tr><td><code>files</code></td><td>any</td><td>observable</td><td>File data populated by <code>onDrop</code> event handler for <code>type: &quot;file&quot;</code> fields</td></tr><tr><td><code>showError</code></td><td>boolean</td><td>observable</td><td>Controls whether error messages are visible</td></tr><tr><td><code>validationErrorStack</code></td><td>string[]</td><td>observable</td><td>Stack of validation error messages</td></tr></tbody></table><hr><h2 id="occurrence-strategy" tabindex="-1">Occurrence Strategy <a class="header-anchor" href="#occurrence-strategy" aria-label="Permalink to &quot;Occurrence Strategy&quot;">​</a></h2><p>Some computed props use different aggregation strategies when checking nested fields:</p><table tabindex="0"><thead><tr><th>Property</th><th>Strategy</th><th>Meaning</th></tr></thead><tbody><tr><td><code>isValid</code>, <code>isPristine</code>, <code>isDefault</code>, <code>isEmpty</code></td><td><strong>every</strong></td><td>Must be <code>true</code> for ALL nested fields</td></tr><tr><td><code>hasError</code>, <code>isDirty</code>, <code>focused</code>, <code>blurred</code>, <code>touched</code></td><td><strong>some</strong></td><td><code>true</code> if ANY nested field is <code>true</code></td></tr></tbody></table>',36)])])}const b=d(a,[["render",c]]);export{p as __pageData,b as default};
